const body = $input.first().json.body || $input.first().json;
const query = body.query || '';
const userId = body.userId || 'unknown';

// 模拟搜索结果（实际应调用搜索 API）
const results = [
  {
    title: `关于「${query}」的行业报告`,
    content: `这是一份关于${query}的详细分析报告，包含市场趋势、竞争格局和发展建议。`,
    source: '行业报告',
    relevance: 0.95,
  },
  {
    title: `${query}最佳实践指南`,
    content: `总结了${query}领域的最佳实践，包括技术选型、架构设计和团队协作。`,
    source: '技术博客',
    relevance: 0.82,
  },
  {
    title: `${query}案例分析`,
    content: `分析了多个成功案例，总结了关键成功因素和常见陷阱。`,
    source: '案例库',
    relevance: 0.75,
  },
];

return [{
  json: {
    query,
    userId,
    results,
    total: results.length,
    message: `找到 ${results.length} 条相关结果`,
  }
}];
